import{_ as t,c as o,a2 as s,o as i}from"./chunks/framework.DPuwY6B9.js";const h=JSON.parse('{"title":"GitHub Actions","description":"GitHub Actions enables us to create custom software development lifecycle workflows directly in the GitHub repository.","frontmatter":{"title":"GitHub Actions","description":"GitHub Actions enables us to create custom software development lifecycle workflows directly in the GitHub repository."},"headers":[],"relativePath":"Languages/CI-CD/Github_Actions.md","filePath":"Languages/CI-CD/Github_Actions.md","lastUpdated":1661720189000}'),n={name:"Languages/CI-CD/Github_Actions.md"};function a(r,e,l,c,u,p){return i(),o("div",null,e[0]||(e[0]=[s('<h1 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to &quot;GitHub Actions&quot;">​</a></h1><p>Github Actions enables us to create custom software development lifecycle workflows directly in the Github repository.</p><p>It is a platform to <em>automate developer (any users) workflows</em>.</p><p>How GitHub Actions automate workflows?</p><ul><li>When something happens <em>in or to the repository</em>.In GitHub these are know as GitHub events such as <em>Pull Requests</em>, <em>Issue created</em>, <em>New Contributers, etc.</em>.</li><li>Listen to these events and trigger workflow. <em>Automatic actions</em> are executed in response.</li></ul><p>Some examples of workflows:</p><ul><li>Running tests, linting and other tasks whenever something happens to the repository.</li></ul><p>Most common workflow includes CI/CD pipelines.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p><strong>Commit code --&gt; Test --&gt; Build --&gt; Push --&gt; Deploy</strong></p></div><p>Why use GitHub Actions as a CI/CD tool?</p><ul><li>use <strong>same tool</strong> instead of third-party integration if the code already exists in GitHub.</li><li>setting up pipelines are <strong>easy</strong>.</li><li><strong>developers focused</strong>.</li></ul><h2 id="syntax-used-for-github-actions" tabindex="-1">Syntax used for GitHub Actions <a class="header-anchor" href="#syntax-used-for-github-actions" aria-label="Permalink to &quot;Syntax used for GitHub Actions&quot;">​</a></h2><p><strong>YAML</strong> file is used for writing the configuration file.</p><ul><li><code>name</code>: Displayed on repository&#39;s action page (optional).</li><li><code>on</code>: Name of GitHub event that triggers the workflow.</li><li><code>jobs</code>: One or more jobs can be written. Groups a set of actions which run in a sequence of tasks (steps).</li><li><code>uses</code>: Selects the action.</li></ul>',14)]))}const m=t(n,[["render",a]]);export{h as __pageData,m as default};
